-- Advisor access pattern: get advisor + clients
CREATE INDEX idx_advisor ON advisory_entities (
    data.advisorId.number()
);

-- Account access pattern: get holdings + transactions
CREATE INDEX idx_account ON advisory_entities (
    data.accountId.number()
);

-- Symbol access pattern: find holdings across all accounts
CREATE INDEX idx_symbol ON advisory_entities (
    data.symbol.string()
);

-- Use the symbol index to find all AAPL holdings across accounts
SELECT data.accountId.number() AS account_id,
       data.quantity.number() AS quantity,
       data.marketValue.number() AS market_value
FROM advisory_entities
WHERE data.symbol.string() = 'AAPL'
  AND data.entityType.string() = 'holding';

